patch:
diff -Nrup 1/drivers/net/tg3.c 2/drivers/net/tg3.c
--- 1/drivers/net/tg3.c	2009-03-23 16:12:14.000000000 -0700
+++ 2/drivers/net/tg3.c	2009-05-04 10:45:37.000000000 -0700
@@ -5038,12 +5038,12 @@ tg3_tso_bug_end:
 static int tg3_start_xmit_dma_bug(struct sk_buff *skb, struct net_device *dev)
 {
 	struct tg3 *tp = netdev_priv(dev);
-	u32 len, entry, base_flags, mss;
+	u32 len, last_len, entry, base_flags, mss;
 	struct skb_shared_info *sp;
 	int would_hit_hwbug;
 	dma_addr_t mapping;

-	len = skb_headlen(skb);
+	len = last_len = skb_headlen(skb);

 	/* We are running in BH disabled context with netif_tx_lock
 	 * and TX reclaim runs via tp->napi.poll inside of a software
@@ -5164,6 +5164,11 @@ static int tg3_start_xmit_dma_bug(struct
 			if (tg3_40bit_overflow_test(tp, mapping, len))
 				would_hit_hwbug = 1;

+			if (last_len + len < 8)
+				would_hit_hwbug = 1;
+
+			last_len = len;
+
 			if (tp->tg3_flags2 & TG3_FLG2_HW_TSO)
 				tg3_set_txd(tp, entry, mapping, len,
 					    base_flags, (i == last)|(mss << 1));
